import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import apiService from '../services/apiService';
import {
    Container,
    Paper,
    Typography,
    Box,
    Button,
    CircularProgress,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    Accordion,
    AccordionSummary,
    AccordionDetails,
    Chip,
    Grid
} from '@mui/material';
import MicIcon from '@mui/icons-material/Mic';
import StopIcon from '@mui/icons-material/Stop';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import HelpOutlineIcon from '@mui/icons-material/HelpOutline';
import { Editor } from '@monaco-editor/react';

const CodeTranscriptionPage = () => {
    const { user } = useAuth();
    const [isRecording, setIsRecording] = useState(false);
    const [transcribedCode, setTranscribedCode] = useState('');
    const [loading, setLoading] = useState(false);
    const [language, setLanguage] = useState('python');
    const [compileOutput, setCompileOutput] = useState('');
    const [compiling, setCompiling] = useState(false);
    const mediaRecorderRef = useRef(null);
    const audioChunksRef = useRef([]);

    useEffect(() => {
        // Initialize any necessary audio/transcription services here
    }, []);

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const mediaRecorder = new MediaRecorder(stream);
            mediaRecorderRef.current = mediaRecorder;
            audioChunksRef.current = [];

            mediaRecorder.ondataavailable = (e) => {
                if (e.data.size > 0) {
                    audioChunksRef.current.push(e.data);
                }
            };

            mediaRecorder.onstop = async () => {
                const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
                await handleTranscribe(audioBlob);
            };

            mediaRecorder.start();
            setIsRecording(true);
        } catch (error) {
            console.error('Failed to start recording:', error);
            alert('Failed to access microphone. Please check permissions.');
        }
    };

    const stopRecording = async () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
            mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
        }
    };

    const handleTranscribe = async (audioBlob) => {
        setLoading(true);
        try {
            const result = await apiService.transcribeAudio(audioBlob);
            if (result.transcript) {
                setTranscribedCode(prev => (prev ? prev + '\n' : '') + result.transcript);
            }
        } catch (e) {
            console.error('Transcription failed', e);
            alert('Transcription failed');
        }
        setLoading(false);
    };

    const addNewLine = () => {
        setTranscribedCode(prev => prev + '\n');
    };

    const clearCode = () => {
        setTranscribedCode('');
    };

    const voiceKeywords = {
        "Brackets & Parentheses": [
            { say: "open parenthesis", gets: "(" },
            { say: "close parenthesis", gets: ")" },
            { say: "open bracket", gets: "[" },
            { say: "close bracket", gets: "]" },
            { say: "open brace", gets: "{" },
            { say: "close brace", gets: "}" },
            { say: "open angle bracket", gets: "<" },
            { say: "close angle bracket", gets: ">" }
        ],
        "Operators": [
            { say: "plus", gets: "+" },
            { say: "minus", gets: "-" },
            { say: "times", gets: "*" },
            { say: "divide", gets: "/" },
            { say: "modulo", gets: "%" },
            { say: "power", gets: "**" },
            { say: "floor divide", gets: "//" },
            { say: "equals", gets: "=" },
            { say: "plus equals", gets: "+=" },
            { say: "minus equals", gets: "-=" },
            { say: "times equals", gets: "*=" }
        ],
        "Comparisons": [
            { say: "double equals", gets: "==" },
            { say: "not equal", gets: "!=" },
            { say: "less than", gets: "<" },
            { say: "greater than", gets: ">" },
            { say: "less than or equal to", gets: "<=" },
            { say: "greater than or equal to", gets: ">=" },
            { say: "right arrow", gets: "->" }
        ],
        "Logical": [
            { say: "and", gets: " and " },
            { say: "or", gets: " or " },
            { say: "not", gets: " not " },
            { say: "logical and", gets: "&&" },
            { say: "logical or", gets: "||" }
        ],
        "Punctuation": [
            { say: "semicolon", gets: ";" },
            { say: "colon", gets: ":" },
            { say: "comma", gets: "," },
            { say: "period", gets: "." },
            { say: "exclamation mark", gets: "!" },
            { say: "question mark", gets: "?" },
            { say: "underscore", gets: "_" },
            { say: "hash", gets: "#" },
            { say: "at", gets: "@" }
        ],
        "Quotes & Strings": [
            { say: "double quote", gets: '"' },
            { say: "single quote", gets: "'" },
            { say: "backtick", gets: "`" }
        ],
        "Special Commands": [
            { say: "new line", gets: "\\n (line break)" },
            { say: "tab", gets: "\\t (tab)" },
            { say: "space", gets: " (space)" }
        ]
    };

    return (
        <Container maxWidth="lg">
            <Box sx={{ mt: 4 }}>
                <Typography variant="h4" component="h1" gutterBottom>
                    Live Code Transcription{user?.name ? ` — Hello, ${user.name}` : ''}
                </Typography>
                <Typography color="textSecondary" paragraph>
                    Speak your code and watch it appear in real-time
                </Typography>

                <Box sx={{ display: 'flex', gap: 2, mb: 3, flexWrap: 'wrap' }}>
                    <FormControl sx={{ minWidth: 200 }}>
                        <InputLabel>Language</InputLabel>
                        <Select value={language} label="Language" onChange={(e) => setLanguage(e.target.value)}>
                            <MenuItem value="python">Python</MenuItem>
                            <MenuItem value="javascript">JavaScript</MenuItem>
                            <MenuItem value="java">Java</MenuItem>
                            <MenuItem value="cpp">C++</MenuItem>
                        </Select>
                    </FormControl>
                    <Button
                        variant="contained"
                        color={isRecording ? "secondary" : "primary"}
                        startIcon={isRecording ? <StopIcon /> : <MicIcon />}
                        onClick={isRecording ? stopRecording : startRecording}
                        disabled={loading}
                    >
                        {isRecording ? 'Stop Recording' : 'Start Recording'}
                    </Button>
                    <Button
                        variant="outlined"
                        onClick={addNewLine}
                        disabled={loading}
                    >
                        Add New Line
                    </Button>
                    <Button
                        variant="outlined"
                        color="error"
                        onClick={clearCode}
                        disabled={loading}
                    >
                        Clear
                    </Button>
                </Box>

                {/* Voice Keywords Guide */}
                <Box sx={{ mb: 3 }}>
                    <Accordion>
                        <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                                <HelpOutlineIcon color="primary" />
                                <Typography variant="h6">Voice Keywords Guide</Typography>
                                <Typography variant="body2" color="textSecondary">
                                    - What to say for symbols and operators
                                </Typography>
                            </Box>
                        </AccordionSummary>
                        <AccordionDetails>
                            <Grid container spacing={3}>
                                {Object.entries(voiceKeywords).map(([category, keywords]) => (
                                    <Grid item xs={12} md={6} lg={4} key={category}>
                                        <Paper sx={{ p: 2, height: '100%' }}>
                                            <Typography variant="subtitle1" gutterBottom color="primary" sx={{ fontWeight: 'bold' }}>
                                                {category}
                                            </Typography>
                                            <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                                                {keywords.map((item, idx) => (
                                                    <Box key={idx} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                                        <Typography variant="body2" sx={{ fontStyle: 'italic' }}>
                                                            "{item.say}"
                                                        </Typography>
                                                        <Chip 
                                                            label={item.gets} 
                                                            size="small" 
                                                            variant="outlined"
                                                            sx={{ fontFamily: 'monospace' }}
                                                        />
                                                    </Box>
                                                ))}
                                            </Box>
                                        </Paper>
                                    </Grid>
                                ))}
                            </Grid>
                            <Box sx={{ mt: 2, p: 2, bgcolor: 'background.default', borderRadius: 1 }}>
                                <Typography variant="body2" color="textSecondary">
                                    <strong>Tips:</strong>
                                    <br />• Speak clearly and pause briefly between symbols
                                    <br />• Say "new line" to go to the next line
                                    <br />• Use "space" for explicit spacing between words
                                    <br />• The system automatically handles common programming patterns
                                </Typography>
                            </Box>
                        </AccordionDetails>
                    </Accordion>
                </Box>

                {loading && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 2 }}>
                        <CircularProgress size={20} />
                        <Typography>Transcribing...</Typography>
                    </Box>
                )}

                <Paper elevation={3} sx={{ height: '60vh' }}>
                    <Editor
                        height="100%"
                        defaultLanguage={language === 'cpp' ? 'cpp' : language}
                        value={transcribedCode}
                        options={{
                            readOnly: loading,
                            minimap: { enabled: false },
                            fontSize: 14
                        }}
                        onChange={(value) => setTranscribedCode(value)}
                    />
                </Paper>
            </Box>
        </Container>
    );
};

export default CodeTranscriptionPage;
